import{_ as a,o as e,c as r,a2 as l}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"白塔与琼华岛","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/beihai/baita.md","filePath":"landmarks/beihai/baita.md","lastUpdated":1784720050000}'),o={name:"landmarks/beihai/baita.md"};function n(i,t,s,g,d,h){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="白塔与琼华岛" tabindex="-1">白塔与琼华岛 <a class="header-anchor" href="#白塔与琼华岛" aria-label="Permalink to &quot;白塔与琼华岛&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1621871183199-4ec39bb3c41c?w=1200&amp;q=80" alt="白塔与琼华岛"></p><blockquote><p>碧波中央，一岛独秀；岛巅白塔，鎏金宝顶直指苍穹——这是北海的眼睛，也是北京城的天际坐标。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><strong>琼华岛</strong>位于北海太液池南部，是全园的布局中心与精神所在。自辽金以来，这里便是皇家苑囿的核心，元代忽必烈营建大都时更以琼华岛为基准点，确立了整座都城的中轴格局。岛上林木葱茏、殿宇层叠，亭台楼阁依山就势，将北方山水的雄浑与江南园林的秀美熔于一炉。</p><p>耸立于琼华岛之巅的<strong>白塔</strong>，是北海乃至整个北京城最醒目的地标。它建于<strong>清顺治八年（1651年）</strong>，是在辽金&quot;广寒殿&quot;旧址上兴建的一座<strong>藏式喇嘛塔</strong>，通体洁白，高<strong>35.9米</strong>，塔顶覆以鎏金宝顶，在阳光下熠熠生辉。</p><p>登临琼华岛而四望，南可望故宫角楼与中南海的碧波，北可眺景山万春亭的琉璃，东眺可见团城古木，西眺则有五龙亭凌波。可以说，琼华岛是读懂北京中轴线与皇家苑囿格局的最佳观景点。</p><p>从造园思想看，北海承袭了中国古典园林&quot;<strong>一池三山</strong>&quot;的传统格局——以一片大湖（太液池）象征东海，以湖中及周边的琼华岛、团城、犀山台等象征海上仙山&quot;蓬莱、方丈、瀛洲&quot;。这一源自秦汉的仙境意象，经辽金元明清历代营建，最终凝定为今日&quot;白塔凌波、仙山在望&quot;的经典景观，琼华岛正是这座人间仙岛的灵魂。</p><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">辽代</td><td style="text-align:left;">始建离宫别苑，岛上营建&quot;瑶屿&quot;行宫</td></tr><tr><td style="text-align:left;">金代</td><td style="text-align:left;">扩建为皇家苑囿，建&quot;广寒殿&quot;等仙山楼阁</td></tr><tr><td style="text-align:left;">元代</td><td style="text-align:left;">忽必烈以琼华岛为中心营建大都，改名&quot;万寿山&quot;</td></tr><tr><td style="text-align:left;">清顺治八年（1651）</td><td style="text-align:left;">于广寒殿旧址建藏式白塔，岛以塔名</td></tr><tr><td style="text-align:left;">清乾隆年间</td><td style="text-align:left;">大修琼华岛，增建漪澜堂、阅古楼诸景</td></tr><tr><td style="text-align:left;">当代</td><td style="text-align:left;">列为全国重点文物保护单位，对外开放</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><h3 id="白塔" tabindex="-1">白塔 <a class="header-anchor" href="#白塔" aria-label="Permalink to &quot;白塔&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>建成年代</strong></td><td style="text-align:left;">清顺治八年（1651年）</td></tr><tr><td style="text-align:left;"><strong>前身</strong></td><td style="text-align:left;">辽金&quot;广寒殿&quot;旧址</td></tr><tr><td style="text-align:left;"><strong>形制</strong></td><td style="text-align:left;">藏式喇嘛塔（覆钵式）</td></tr><tr><td style="text-align:left;"><strong>高度</strong></td><td style="text-align:left;">35.9米</td></tr><tr><td style="text-align:left;"><strong>塔顶</strong></td><td style="text-align:left;">鎏金宝顶，由天盘、地盘、日、月、火焰组成</td></tr><tr><td style="text-align:left;"><strong>结构</strong></td><td style="text-align:left;">砖石结构，塔身洁白，南面设&quot;眼光门&quot;（时轮金刚门）</td></tr></tbody></table><p>白塔由塔基、塔身、相轮、宝顶四部分组成。塔基为高大的汉白玉须弥座，束腰处雕有精美的纹饰；塔身呈上圆下方的覆钵形，四面设佛龛，南面的&quot;眼光门&quot;内雕时轮金刚像，象征佛法之眼遍照十方；其上为十三层相轮（俗称&quot;十三天&quot;），层层收分；最顶为鎏金天盘、地盘与日月火焰宝顶，象征佛教的宇宙观。</p><h3 id="琼华岛诸景" tabindex="-1">琼华岛诸景 <a class="header-anchor" href="#琼华岛诸景" aria-label="Permalink to &quot;琼华岛诸景&quot;">​</a></h3><ul><li><strong>永安寺</strong>：白塔脚下的藏传佛教寺院，依山而建、殿宇三重。自南而北依次为<strong>法轮殿、正觉殿、普安殿</strong>，红墙黄瓦、层层递高，是通往白塔的主要朝圣轴线。</li><li><strong>漪澜堂</strong>：位于琼华岛北麓，是<strong>乾隆皇帝读书静养</strong>之处。仿镇江金山寺&quot;寺裹山&quot;格局而建，堂周环以双层长廊，凭栏可览太液池全景。</li><li><strong>琼岛春阴碑</strong>：立于琼华岛东麓，碑身镌刻乾隆御笔&quot;<strong>琼岛春阴</strong>&quot;四字，是&quot;<strong>燕京八景</strong>&quot;之一。</li><li><strong>阅古楼</strong>：位于琼华岛西北，平面呈半月形的两层楼阁，楼内四壁嵌满《三希堂法帖》石刻，收藏自魏晋至明代的书法名迹数百件。</li></ul><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="白塔为何而建-两种传说" tabindex="-1">白塔为何而建：两种传说 <a class="header-anchor" href="#白塔为何而建-两种传说" aria-label="Permalink to &quot;白塔为何而建：两种传说&quot;">​</a></h3><p>关于白塔的兴建，历来有<strong>两说</strong>。其一为<strong>镇邪压龙</strong>之说：相传北京地下有&quot;海眼&quot;，常有水患之虞，建塔以镇之，取&quot;镇压龙脉、安定都城&quot;之意。其二为<strong>顺治向佛</strong>之说：清世祖顺治帝笃信藏传佛教，曾召西藏高僧入京，为供奉舍利、弘扬佛法，遂于广寒殿旧址上兴建这座藏式喇嘛塔。两说并行不悖，一为民间附会，一为正史所载。</p><h3 id="广寒殿的前世-从仙山到佛国" tabindex="-1">广寒殿的前世：从仙山到佛国 <a class="header-anchor" href="#广寒殿的前世-从仙山到佛国" aria-label="Permalink to &quot;广寒殿的前世：从仙山到佛国&quot;">​</a></h3><p>白塔并非凭空而起，它的脚下曾是金代著名的<strong>广寒殿</strong>——一座模仿海上仙山、供帝王游宴的华美宫殿。元代时广寒殿仍是皇家宴饮之所，相传忽必烈曾在此大宴群臣，殿中还陈列着那只后来流落民间的渎山大玉海（见<a href="/beijing-travel-guide/landmarks/beihai/tuancheng.html">团城</a>）。至明代广寒殿倾圮，清顺治年间改为白塔，琼华岛的主题也由此从道家的&quot;蓬莱仙岛&quot;转变为佛家的&quot;清净梵境&quot;。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>登塔俯瞰</strong>：琼华岛是全园制高点，南望故宫角楼与中南海，北眺景山万春亭，红墙金瓦尽收眼底。</li><li><strong>鎏金宝顶</strong>：仰观塔顶十三天之上的鎏金日月宝顶，在阳光下金光灿灿，是整座白塔最庄严的部分。</li><li><strong>永安寺三重殿</strong>：沿法轮殿、正觉殿、普安殿拾级而上，感受依山筑寺的空间层次与朝圣氛围。</li><li><strong>琼岛春阴碑</strong>：寻觅燕京八景之一的御碑，体会&quot;春阴&quot;二字的诗意。</li><li><strong>漪澜堂凭栏</strong>：在乾隆读书处凭栏北望，太液池水天一色，双层长廊环抱，是岛上最宜观景之所。</li><li><strong>阅古楼法帖</strong>：若时间充裕，可入阅古楼细览《三希堂法帖》石刻，品味千年书法墨韵。</li></ol><h2 id="拍照机位" tabindex="-1">拍照机位 <a class="header-anchor" href="#拍照机位" aria-label="Permalink to &quot;拍照机位&quot;">​</a></h2><ol><li><strong>南岸回望</strong>：从南岸隔太液池拍白塔全景，碧水白塔倒影相映，是最经典的一幅。</li><li><strong>漪澜堂长廊</strong>：双层长廊的廊柱与漏窗是现成的框景，可拍出层次丰富的白塔侧影。</li><li><strong>塔下仰拍</strong>：白塔脚下仰拍鎏金宝顶与蓝天，庄严挺拔，尽显喇嘛塔的垂直之美。</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li><strong>购联票登岛</strong>：琼华岛（含白塔、永安寺）需购联票（20元含琼岛、团城），单买门票10元不含登岛。</li><li><strong>顺时针环岛</strong>：建议从南岸过永安桥上山，依次游永安寺、白塔，再下山至漪澜堂、琼岛春阴碑、阅古楼，不走回头路。</li><li><strong>下午登塔</strong>：下午阳光西斜，从岛上回望故宫、景山的逆光与侧光最适合拍照。</li><li><strong>联游北岸</strong>：下山后可沿湖游<a href="/beijing-travel-guide/landmarks/beihai/jiulongbi.html">九龙壁</a>、<a href="/beijing-travel-guide/landmarks/beihai/wulongting.html">五龙亭</a>、<a href="/beijing-travel-guide/landmarks/beihai/xitianfanjing.html">西天梵境</a>、<a href="/beijing-travel-guide/landmarks/beihai/jingxinzhai.html">静心斋</a>。</li><li><strong>联游团城</strong>：琼华岛南侧过永安桥即达<a href="/beijing-travel-guide/landmarks/beihai/tuancheng.html">团城</a>，可顺路一游白玉佛与渎山大玉海。</li><li><strong>留意体力</strong>：琼华岛台阶较多，登塔往返约需半小时，穿舒适的鞋。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：白塔可以进去登临吗？</strong></p><p>白塔本身为宗教圣物，通常不入内攀登；但琼华岛是全园制高点，登山即可俯瞰故宫、景山、中南海的开阔全景，视野极佳。</p><p><strong>Q：为什么白塔是白色的喇嘛塔，而不是传统楼阁式塔？</strong></p><p>白塔建于清顺治年间，顺治帝笃信藏传佛教，故采用藏式覆钵喇嘛塔的形制，与内地常见的楼阁式塔风格迥异，是汉藏文化交融的见证。</p><p><strong>Q：琼岛春阴碑的&quot;春阴&quot;是什么意思？</strong></p><p>&quot;春阴&quot;描绘的是春日琼岛林木葱茏、烟岚如黛的清幽意境，是乾隆钦定的&quot;燕京八景&quot;之一，碑为乾隆御笔亲题。</p><hr><p><strong>📍 位置</strong>：北海太液池南部，全园布局中心 <strong>⏱️ 建议游览</strong>：1-1.5小时 <strong>🔗 相邻</strong>：<a href="/beijing-travel-guide/landmarks/beihai/jiulongbi.html">九龙壁</a>、<a href="/beijing-travel-guide/landmarks/beihai/wulongting.html">五龙亭</a>、<a href="/beijing-travel-guide/landmarks/beihai/xitianfanjing.html">西天梵境</a>（环湖北岸） <strong>🔗 相邻</strong>：<a href="/beijing-travel-guide/landmarks/beihai/tuancheng.html">团城</a>（琼华岛南侧，过永安桥可达） <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/beihai/">北海公园概览</a></p>',36)])])}const b=a(o,[["render",n]]);export{q as __pageData,b as default};
